// app/admin/page.tsx
"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import Image from "next/image";
import {
  PlusCircle, Edit3, Trash2, Eye, Heart, MessageCircle,
  BarChart3, Newspaper, AlertTriangle, X, CheckCircle2,
} from "lucide-react";
import { Post, getPosts, deletePost } from "@/lib/firebase/posts";
import { fetchDashboardStats } from "@/app/actions/stats";
import { formatDateEn } from "@/lib/utils/formatDate";
import Spinner from "@/components/ui/Spinner";
import { useLanguage } from "@/lib/context/LanguageContext";

// ΓöÇΓöÇΓöÇ Delete Confirmation Modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function DeleteModal({
  post,
  onConfirm,
  onCancel,
  deleting,
}: {
  post: Post;
  onConfirm: () => void;
  onCancel: () => void;
  deleting: boolean;
}) {
  const { t } = useLanguage();
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={onCancel}
      />
      {/* Modal */}
      <div className="relative bg-white dark:bg-gray-900 rounded-3xl shadow-2xl w-full max-w-md p-6 animate-in zoom-in-95 fade-in duration-200">
        {/* Icon */}
        <div className="flex items-center justify-center w-14 h-14 bg-red-100 dark:bg-red-900/30 rounded-2xl mx-auto mb-4">
          <AlertTriangle className="w-7 h-7 text-red-600" />
        </div>

        <h2 className="text-lg font-black text-gray-900 dark:text-white text-center mb-1">
          {t("deletePostConfirm")}
        </h2>
        <p className="text-sm text-gray-500 dark:text-gray-400 text-center mb-4">
          {t("permanentAction")}
        </p>

        {/* Post preview */}
        <div className="flex items-center gap-3 p-3 bg-gray-50 dark:bg-gray-800 rounded-2xl mb-5 border border-gray-100 dark:border-gray-700">
          {post.imageUrl && (
            <div className="relative w-12 h-9 rounded-lg overflow-hidden flex-shrink-0">
              <Image src={post.imageUrl} alt={post.title} fill className="object-cover" sizes="48px" />
            </div>
          )}
          <p className="text-sm font-semibold text-gray-800 dark:text-gray-200 line-clamp-2 flex-1">
            {post.title}
          </p>
        </div>

        <div className="flex gap-3">
          <button
            onClick={onCancel}
            disabled={deleting}
            className="flex-1 py-3 px-4 bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-bold rounded-2xl hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
          >
            {t("cancel")}
          </button>
          <button
            onClick={onConfirm}
            disabled={deleting}
            className="flex-1 py-3 px-4 bg-red-600 hover:bg-red-700 text-white font-bold rounded-2xl transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {deleting ? (
              <><Spinner size="sm" /> {t("deleting")}</>
            ) : (
              <><Trash2 className="w-4 h-4" /> {t("yesDelete")}</>
            )}
          </button>
        </div>

        {/* Close button */}
        <button
          onClick={onCancel}
          className="absolute top-4 right-4 p-1.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-colors"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Toast ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function Toast({ msg, visible }: { msg: string; visible: boolean }) {
  if (!visible) return null;
  return (
    <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999] flex items-center gap-2 px-5 py-3 bg-green-600 text-white rounded-2xl shadow-2xl text-sm font-semibold animate-in slide-in-from-bottom-4 fade-in duration-200">
      <CheckCircle2 className="w-4 h-4" />
      {msg}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Main Dashboard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function AdminDashboard() {
  const { t, language } = useLanguage();
  const [posts, setPosts]       = useState<Post[]>([]);
  const [loading, setLoading]   = useState(true);
  const [deleteTarget, setDeleteTarget] = useState<Post | null>(null);
  const [deleting, setDeleting] = useState(false);
  const [toast, setToast]       = useState({ msg: "", visible: false });

  const [stats, setStats]       = useState({
    totalPosts: 0,
    totalLikes: 0,
    totalViews: 0,
    totalComments: 0,
  });

  const fetchPosts = async () => {
    setLoading(true);
    try {
      // Fetch all posts (including drafts) and global aggregation stats
      // We use a Server Action for stats to ensure reliability and bypass client limits
      const [{ posts: fetched }, globalStats] = await Promise.all([
        getPosts(undefined, 100, true),
        fetchDashboardStats()
      ]);
      setPosts(fetched);
      setStats(globalStats);
    } catch (err) {
      console.error("Failed to load posts:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchPosts(); }, []);

  const showToast = (msg: string) => {
    setToast({ msg, visible: true });
    setTimeout(() => setToast(t => ({ ...t, visible: false })), 3000);
  };

  const confirmDelete = async () => {
    if (!deleteTarget) return;
    setDeleting(true);
    try {
      await deletePost(deleteTarget.id);
      await fetchPosts(); // Re-fetch to update both the list and the global stats
      showToast(t("postDeleted"));
    } catch (err) {
      console.error("Delete failed:", err);
      showToast(t("deleteFailed"));
    } finally {
      setDeleting(false);
      setDeleteTarget(null);
    }
  };

  // We now use the stats state populated by getGlobalStats() for true collection totals
  // but keep these for quick checks if needed (though they are redundant now)
  const { totalPosts, totalLikes, totalViews, totalComments } = stats;

  return (
    <>
      <Toast msg={toast.msg} visible={toast.visible} />

      {deleteTarget && (
        <DeleteModal
          post={deleteTarget}
          onConfirm={confirmDelete}
          onCancel={() => !deleting && setDeleteTarget(null)}
          deleting={deleting}
        />
      )}

      <div className="space-y-6">
        {/* ΓöÇΓöÇ Header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div className="flex items-start sm:items-center justify-between gap-4 flex-col sm:flex-row">
          <div>
            <h1 className="text-2xl font-black text-gray-900 dark:text-white flex items-center gap-2">
              <Newspaper className="w-6 h-6 text-red-600" />
              {t("postsDashboard")}
            </h1>
              {totalPosts} {t("postsCountDescription")}
          </div>
          <Link
            href="/admin/create"
            className="flex items-center gap-2 px-5 py-2.5 bg-red-600 hover:bg-red-700 active:scale-95 text-white font-bold rounded-2xl transition-all shadow-lg hover:shadow-red-200 whitespace-nowrap"
          >
            <PlusCircle className="w-4 h-4" />
            {t("newPost")}
          </Link>
        </div>

        {/* ΓöÇΓöÇ Stats ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {[
            { label: t("totalPosts"),   value: totalPosts,      icon: <Newspaper   className="w-5 h-5 text-blue-500" />,   bg: "bg-blue-50 dark:bg-blue-900/20" },
            { label: t("totalLikes"),   value: totalLikes,      icon: <Heart       className="w-5 h-5 text-red-500" />,    bg: "bg-red-50 dark:bg-red-900/20" },
            { label: t("totalViews"),   value: totalViews,      icon: <BarChart3   className="w-5 h-5 text-green-500" />,  bg: "bg-green-50 dark:bg-green-900/20" },
            { label: t("comments"),     value: totalComments,   icon: <MessageCircle className="w-5 h-5 text-purple-500" />, bg: "bg-purple-50 dark:bg-purple-900/20" },
          ].map(stat => (
            <div key={stat.label} className="bg-white dark:bg-gray-900 rounded-2xl p-4 border border-gray-100 dark:border-gray-800 shadow-sm">
              <div className={`inline-flex p-2 rounded-xl mb-2 ${stat.bg}`}>
                {stat.icon}
              </div>
              <p className="text-2xl font-black text-gray-900 dark:text-white leading-none">{stat.value.toLocaleString()}</p>
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{stat.label}</p>
            </div>
          ))}
        </div>

        {/* ΓöÇΓöÇ Posts List ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div className="bg-white dark:bg-gray-900 rounded-2xl border border-gray-100 dark:border-gray-800 overflow-hidden shadow-sm">
          {/* Section header */}
          <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-800/50">
            <h2 className="font-bold text-gray-900 dark:text-white text-sm">
              {t("allPosts")}
            </h2>
            <span className="text-xs text-gray-400 bg-gray-100 dark:bg-gray-700 px-2.5 py-1 rounded-full font-medium">
              {posts.length} {t("total")}
            </span>
          </div>

          {loading ? (
            <div className="flex items-center justify-center py-20">
              <Spinner size="lg" />
            </div>
          ) : posts.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-center">
              <p className="text-5xl mb-3">≡ƒô¡</p>
              <p className="font-semibold text-gray-600 dark:text-gray-400 mb-1">{t("noPosts")}</p>
              <Link href="/admin/create" className="text-sm text-red-600 hover:underline font-medium">
                {t("createFirst")}
              </Link>
            </div>
          ) : (
            <div className="divide-y divide-gray-50 dark:divide-gray-800">
              {posts.map((post, idx) => (
                <div
                  key={post.id}
                  className="flex items-center gap-4 px-4 sm:px-6 py-4 hover:bg-gray-50/80 dark:hover:bg-gray-800/40 transition-colors group"
                >
                  {/* Serial number */}
                  <div className="flex-shrink-0 w-9 h-9 rounded-xl bg-gray-100 dark:bg-gray-800 flex items-center justify-center">
                    <span className="text-xs font-black text-gray-500 dark:text-gray-400">
                      {idx + 1}
                    </span>
                  </div>

                  {/* Thumbnail */}
                  {post.imageUrl ? (
                    <div className="relative w-14 h-11 rounded-xl overflow-hidden flex-shrink-0 shadow-sm">
                      <Image src={post.imageUrl} alt={post.title} fill className="object-cover" sizes="56px" />
                    </div>
                  ) : (
                    <div className="w-14 h-11 rounded-xl bg-gray-100 dark:bg-gray-800 flex-shrink-0 flex items-center justify-center">
                      <Newspaper className="w-5 h-5 text-gray-300" />
                    </div>
                  )}

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-gray-900 dark:text-white line-clamp-1 mb-0.5">
                      {post.title}
                    </p>
                    <div className="flex items-center flex-wrap gap-x-3 gap-y-1">
                      {/* Status badge */}
                      <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-bold ${
                        post.status === "published"
                          ? "bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400"
                          : post.status === "draft"
                          ? "bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400"
                          : "bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400"
                      }`}>
                        {post.status === "published"
                          ? t("published")
                          : post.status === "draft"
                          ? t("draft")
                          : t("scheduled")}
                      </span>
                      {/* Category */}
                      {post.category && (
                        <span className="text-[11px] text-gray-400 font-medium">
                          {t(post.category)}
                        </span>
                      )}
                      {/* Stats */}
                      <span className="hidden sm:flex items-center gap-1 text-[11px] text-gray-400">
                        <Heart className="w-3 h-3" />{post.likesCount}
                      </span>
                      <span className="hidden sm:flex items-center gap-1 text-[11px] text-gray-400">
                        <Eye className="w-3 h-3" />{post.viewsCount}
                      </span>
                      {/* Date */}
                      <span className="hidden lg:block text-[11px] text-gray-400">
                        {formatDateEn(post.createdAt)}
                      </span>
                    </div>
                  </div>

                  {/* Action buttons ΓÇö always visible on mobile, visible on hover for desktop */}
                  <div className="flex items-center gap-1.5 flex-shrink-0">
                    {/* View */}
                    <Link
                      href={`/post/${post.slug}`}
                      target="_blank"
                      title={t("viewPost")}
                      className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl transition-all"
                    >
                      <Eye className="w-4 h-4" />
                    </Link>

                    {/* Edit */}
                    <Link
                      href={`/admin/edit/${post.id}`}
                      title={t("editPost")}
                      className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold text-green-700 dark:text-green-400 bg-green-50 dark:bg-green-900/20 hover:bg-green-100 dark:hover:bg-green-900/40 rounded-xl transition-all border border-green-200 dark:border-green-800"
                    >
                      <Edit3 className="w-3.5 h-3.5" />
                      <span className="hidden sm:inline">{t("edit")}</span>
                    </Link>

                    {/* Delete */}
                    <button
                      onClick={() => setDeleteTarget(post)}
                      title={t("deletePost")}
                      className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-bold text-red-700 dark:text-red-400 bg-red-50 dark:bg-red-900/20 hover:bg-red-100 dark:hover:bg-red-900/40 rounded-xl transition-all border border-red-200 dark:border-red-800"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                      <span className="hidden sm:inline">{t("delete")}</span>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}

// components/admin/PostForm.tsx
"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import { useRouter } from "next/navigation";
import {
  Plus, X, Save, Loader2, CheckCircle2, AlertCircle,
  Clock, FileText, Send, ChevronDown, Calendar,
} from "lucide-react";
import ImageKitUploader from "./ImageKitUploader";
import { createPost, updatePost, Post, PostStatus } from "@/lib/firebase/posts";
import { getCustomCategories, saveCategory, removeCategory as deleteCategory, Category } from "@/lib/firebase/categories";
import { generateSlug } from "@/lib/utils/slugify";
import { useLanguage } from "@/lib/context/LanguageContext";

// ΓöÇΓöÇΓöÇ Categories ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const CATEGORIES = [
  { value: "bihar",         label: "αñ¼αñ┐αñ╣αñ╛αñ░",        labelEn: "Bihar" },
  { value: "jharkhand",    label: "αñ¥αñ╛αñ░αñûαñéαñí",        labelEn: "Jharkhand" },
  { value: "politics",     label: "αñ░αñ╛αñ£αñ¿αÑÇαññαñ┐",       labelEn: "Politics" },
  { value: "entertainment",label: "αñ«αñ¿αÑïαñ░αñéαñ£αñ¿",       labelEn: "Entertainment" },
  { value: "sports",       label: "αñûαÑçαñ▓",           labelEn: "Sports" },
  { value: "crime",        label: "αñòαÑìαñ░αñ╛αñçαñ«",         labelEn: "Crime" },
  { value: "business",     label: "αñ╡αÑìαñ»αñ╛αñ¬αñ╛αñ░",        labelEn: "Business" },
  { value: "education",    label: "αñ╢αñ┐αñòαÑìαñ╖αñ╛",         labelEn: "Education" },
  { value: "health",       label: "αñ╕αÑìαñ╡αñ╛αñ╕αÑìαñÑαÑìαñ»",       labelEn: "Health" },
  { value: "national",     label: "αñ░αñ╛αñ╖αÑìαñƒαÑìαñ░αÑÇαñ»",       labelEn: "National" },
  { value: "international",label: "αñàαñéαññαñ░αñ░αñ╛αñ╖αÑìαñƒαÑìαñ░αÑÇαñ»",   labelEn: "International" },
];

// ΓöÇΓöÇΓöÇ Toast ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface ToastState {
  message: string;
  type: "success" | "error" | "info";
  visible: boolean;
}

function Toast({ toast }: { toast: ToastState }) {
  if (!toast.visible) return null;
  const colors = {
    success: "bg-green-600 text-white",
    error:   "bg-red-600 text-white",
    info:    "bg-blue-600 text-white",
  };
  const icons = {
    success: <CheckCircle2 className="w-4 h-4" />,
    error:   <AlertCircle className="w-4 h-4" />,
    info:    <Clock className="w-4 h-4" />,
  };
  return (
    <div className={`fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999] flex items-center gap-2.5 px-5 py-3 rounded-2xl shadow-2xl text-sm font-semibold animate-in slide-in-from-bottom-4 fade-in duration-300 ${colors[toast.type]}`}>
      {icons[toast.type]}
      {toast.message}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Field error indicator ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function FieldError({ msg }: { msg?: string }) {
  if (!msg) return null;
  return (
    <p className="mt-1.5 text-xs text-red-500 flex items-center gap-1">
      <AlertCircle className="w-3 h-3 flex-shrink-0" />
      {msg}
    </p>
  );
}

// ΓöÇΓöÇΓöÇ Props ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface PostFormProps {
  post?: Post;
}

// ΓöÇΓöÇΓöÇ Validation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface FieldErrors {
  title?: string;
  content?: string;
  category?: string;
  image?: string;
  scheduleDate?: string;
}

// ΓöÇΓöÇΓöÇ Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function PostForm({ post }: PostFormProps) {
  const { t, language } = useLanguage();
  const router = useRouter();

  // form state
  const [title,        setTitle]        = useState(post?.title    || "");
  const [titleHi,      setTitleHi]      = useState(post?.titleHi  || post?.title || "");
  const [titleEn,      setTitleEn]      = useState(post?.titleEn  || "");
  const [content,      setContent]      = useState(post?.content  || "");
  const [contentHi,    setContentHi]    = useState(post?.contentHi || post?.content || "");
  const [contentEn,    setContentEn]    = useState(post?.contentEn || "");
  const [tags,         setTags]         = useState<string[]>(post?.tags || []);
  const [tagsHi,       setTagsHi]       = useState<string[]>(post?.tagsHi || post?.tags || []);
  const [tagsEn,       setTagsEn]       = useState<string[]>(post?.tagsEn || []);
  const [category,     setCategory]     = useState(post?.category || "");
  const [city,         setCity]         = useState(post?.city     || "");
  const [state,        setState]        = useState(post?.state    || "");
  const [eventDate,    setEventDate]    = useState(post?.eventDate || "");
  // Parse stored eventTime (HH:MM) back to 12h parts
  const parseStoredTime = (t: string) => {
    if (!t) return { h: "", m: "00", p: "AM" };
    const [hh, mm] = t.split(":");
    const hour24 = parseInt(hh, 10);
    return {
      h: String(hour24 % 12 || 12),
      m: mm || "00",
      p: hour24 >= 12 ? "PM" : "AM",
    };
  };
  const initTime = parseStoredTime(post?.eventTime || "");
  const [timeHour,   setTimeHour]   = useState(initTime.h);
  const [timeMinute, setTimeMinute] = useState(initTime.m);
  const [timePeriod, setTimePeriod] = useState<"AM"|"PM">(initTime.p as "AM"|"PM");
  // Derived eventTime in HH:MM (24h) for storage
  const eventTime = timeHour
    ? (() => {
        let h = parseInt(timeHour, 10);
        if (timePeriod === "PM" && h !== 12) h += 12;
        if (timePeriod === "AM" && h === 12) h = 0;
        return `${String(h).padStart(2, "0")}:${timeMinute}`;
      })()
    : "";
  const [tagInput,     setTagInput]     = useState("");
  const [imageUrl,     setImageUrl]     = useState(post?.imageUrl || "");
  const [videoUrl,     setVideoUrl]     = useState(post?.videoUrl || "");
  const [publishMode,  setPublishMode]  = useState<PostStatus>(post?.status || "published");
  const [scheduleDate, setScheduleDate] = useState(
    post?.publishAt ? post.publishAt.slice(0, 16) : ""
  );

  // UI state
  const [saving,         setSaving]         = useState(false);
  const [saved,          setSaved]          = useState(false);
  const [fieldErrors,    setFieldErrors]    = useState<FieldErrors>({});
  const [toast,          setToast]          = useState<ToastState>({ message: "", type: "success", visible: false });
  const [modeOpen,       setModeOpen]       = useState(false);
  const [newCatInput,    setNewCatInput]    = useState("");
  const [customCats,     setCustomCats]     = useState<Category[]>([]);
  const [showNewCatBox,  setShowNewCatBox]  = useState(false);
  const [catLoading,     setCatLoading]     = useState(false); // saving a new cat
  const newCatRef = useRef<HTMLInputElement>(null);

  // Load custom categories from Firestore on mount
  useEffect(() => {
    getCustomCategories()
      .then(cats => setCustomCats(cats))
      .catch(() => {}); // fail silently
  }, []);

  // refs for auto-scroll
  const titleRef    = useRef<HTMLDivElement>(null);
  const contentRef  = useRef<HTMLDivElement>(null);
  const categoryRef = useRef<HTMLDivElement>(null);
  const imageRef    = useRef<HTMLDivElement>(null);

  // is form ready to publish? ΓÇö check the active language's required fields
  const currentTitle   = language === "hi" ? titleHi   : (titleEn   || titleHi);
  const currentContent = language === "hi" ? contentHi : (contentEn || contentHi);
  const isReady = currentTitle.trim() && currentContent.trim() && category && (imageUrl || videoUrl);

  // ΓöÇΓöÇ Toast helper ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const showToast = useCallback((message: string, type: ToastState["type"] = "success") => {
    setToast({ message, type, visible: true });
    setTimeout(() => setToast(t => ({ ...t, visible: false })), 3500);
  }, []);

  // ΓöÇΓöÇ Tag helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const addTag = () => {
    const v = tagInput.trim().toLowerCase().replace(/\s+/g, "-");
    if (v && !tags.includes(v)) {
      setTags(prev => [...prev, v]);
      // mirror to the current language's tag list
      if (language === "hi") setTagsHi(prev => [...prev, v]);
      else setTagsEn(prev => [...prev, v]);
    }
    setTagInput("");
  };
  const removeTag = (tag: string) => {
    setTags(prev => prev.filter(t => t !== tag));
    setTagsHi(prev => prev.filter(t => t !== tag));
    setTagsEn(prev => prev.filter(t => t !== tag));
  };
  const handleTagKey = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" || e.key === ",") { e.preventDefault(); addTag(); }
  };

  // ΓöÇΓöÇ Custom category helpers (Firestore-backed) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const addCustomCategory = async () => {
    const raw = newCatInput.trim();
    if (!raw) return;
    const value = raw.toLowerCase().replace(/\s+/g, "-");
    // Don't duplicate built-in or custom
    const alreadyExists =
      CATEGORIES.some(c => c.value === value) ||
      customCats.some(c => c.value === value);

    if (!alreadyExists) {
      const newCat: Category = {
        value,
        label: raw,       // treat input as both Hindi and English
        labelEn: raw,
        isCustom: true,
        createdAt: new Date().toISOString(),
      };
      // Optimistic update
      setCustomCats(prev => [...prev, newCat]);
      // Persist to Firestore
      setCatLoading(true);
      try {
        await saveCategory(newCat);
      } catch (e) {
        console.error("Category save failed:", e);
      } finally {
        setCatLoading(false);
      }
    }
    setCategory(value);
    setFieldErrors(er => ({ ...er, category: undefined }));
    setNewCatInput("");
    setShowNewCatBox(false);
  };
  const handleNewCatKey = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") { e.preventDefault(); addCustomCategory(); }
    if (e.key === "Escape") { setShowNewCatBox(false); setNewCatInput(""); }
  };
  const removeCustomCat = async (value: string) => {
    // Optimistic update
    setCustomCats(prev => prev.filter(c => c.value !== value));
    if (category === value) setCategory("");
    // Delete from Firestore
    try { await deleteCategory(value); } catch (e) { console.error(e); }
  };

  // ΓöÇΓöÇ Uploader callback ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleUpload = (url: string, type: "image" | "video") => {
    if (type === "video") {
      setVideoUrl(url);
      setImageUrl("");
    } else {
      setImageUrl(url);
      setVideoUrl("");
    }
    setFieldErrors(e => ({ ...e, image: undefined }));
  };

  // ΓöÇΓöÇ Validation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // ΓöÇΓöÇΓöÇ Validation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const validate = (): boolean => {
    const errs: FieldErrors = {};
    if (!currentTitle.trim())   { errs.title    = t("title") + " " + t("isRequired"); }
    if (!currentContent.trim()) { errs.content  = t("content") + " " + t("isRequired"); }
    if (!category)       { errs.category = t("selectCategory"); }
    if (!imageUrl && !videoUrl)  { errs.image    = t("uploadImage"); }
    if (publishMode === "scheduled" && !scheduleDate) {
      errs.scheduleDate = t("publishDate");
    }
    setFieldErrors(errs);

    // auto-scroll to first error
    const firstRef = errs.title ? titleRef : errs.content ? contentRef : errs.category ? categoryRef : errs.image ? imageRef : null;
    if (firstRef?.current) {
      firstRef.current.scrollIntoView({ behavior: "smooth", block: "center" });
    }
    return Object.keys(errs).length === 0;
  };

  // ΓöÇΓöÇ Submit ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleSubmit = async (mode: PostStatus = publishMode) => {
    if (saving || saved) return;
    if (!validate()) return;

    setSaving(true);
    try {
      const slug = post?.slug || generateSlug(titleHi || titleEn || title);
      // Always persist bilingual data. Use the current language's value as primary.
      const newTitleHi = language === "hi" ? currentTitle.trim() : (titleHi.trim() || currentTitle.trim());
      const newTitleEn = language === "en" ? currentTitle.trim() : titleEn.trim();
      const newContentHi = language === "hi" ? currentContent.trim() : (contentHi.trim() || currentContent.trim());
      const newContentEn = language === "en" ? currentContent.trim() : contentEn.trim();

      const input = {
        // Keep `title` as the Hindi title for legacy/server-side rendering
        title: newTitleHi || newTitleEn,
        titleHi: newTitleHi || undefined,
        titleEn: newTitleEn || undefined,
        slug,
        content: newContentHi || newContentEn,
        contentHi: newContentHi || undefined,
        contentEn: newContentEn || undefined,
        category,
        city:      city.trim()      || undefined,
        state:     state.trim()     || undefined,
        eventDate: eventDate        || undefined,
        eventTime: eventTime        || undefined,
        tags: tagsHi.length ? tagsHi : tags,
        tagsHi: tagsHi.length ? tagsHi : undefined,
        tagsEn: tagsEn.length ? tagsEn : undefined,
        imageUrl,
        videoUrl,
        status: mode,
        publishAt: mode === "scheduled" ? scheduleDate : undefined,
      };

      if (post) {
        await updatePost(post.id, input);
      } else {
        await createPost(input);
      }

      // Revalidation
      const secret = process.env.NEXT_PUBLIC_REVALIDATE_SECRET;
      if (secret && mode === "published") {
        const revalidateTargets = [
          `/api/revalidate?secret=${secret}&slug=${slug}`,
          `/api/revalidate?secret=${secret}`, 
          ...(category ? [`/api/revalidate?secret=${secret}&tag=${category}`] : []),
        ];
        revalidateTargets.forEach(url =>
          fetch(url, { method: "POST" }).catch(() => {})
        );
      }

      setSaved(true);
      const msg =
        mode === "draft"     ? t("draftSaved")
        : mode === "scheduled" ? t("postScheduled")
        : t("postPublished");

      showToast(msg, mode === "draft" ? "info" : "success");
      setTimeout(() => router.push("/admin"), 1800);
    } catch (err) {
      console.error(err);
      showToast(t("errorOccurred"), "error");
    } finally {
      setSaving(false);
    }
  };

  // ΓöÇΓöÇ Publish button inner content ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const publishBtnContent = () => {
    if (saved)   return <><CheckCircle2 className="w-4 h-4" /> {t("done")}</>;
    if (saving)  return <><Loader2 className="w-4 h-4 animate-spin" /> {t("saving")}</>;
    const modeLabel: Record<PostStatus, string> = {
      published: t("publishNow"),
      draft:     t("saveDraft"),
      scheduled: t("schedule"),
    };
    const icon: Record<PostStatus, React.ReactNode> = {
      published: <Send className="w-4 h-4" />,
      draft:     <FileText className="w-4 h-4" />,
      scheduled: <Calendar className="w-4 h-4" />,
    };
    return <>{icon[publishMode]} {modeLabel[publishMode]}</>;
  };

  const btnColor = saved ? "bg-green-600 hover:bg-green-700" :
    publishMode === "draft" ? "bg-gray-700 hover:bg-gray-800 dark:bg-gray-600 dark:hover:bg-gray-500" :
    "bg-red-600 hover:bg-red-700";

  const categoryLabel = (val: string) => {
    const cat = CATEGORIES.find(c => c.value === val);
    return cat ? (language === "hi" ? cat.label : cat.labelEn) : t("selectCategory");
  };

  return (
    <>
      <Toast toast={toast} />

      {/* ΓöÇΓöÇ Sticky Publish Bar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <div className="fixed bottom-0 left-0 right-0 z-50 sm:hidden bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-700 px-4 py-3 flex items-center gap-3 shadow-2xl">
        <button
          type="button"
          onClick={() => handleSubmit("draft")}
          disabled={saving || saved}
          className="flex-1 flex items-center justify-center gap-2 py-3 bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-bold rounded-xl text-sm hover:bg-gray-200 transition-all disabled:opacity-50"
        >
          <FileText className="w-4 h-4" />
          {t("saveDraft")}
        </button>
        <button
          type="button"
          onClick={() => handleSubmit(publishMode)}
          disabled={saving || saved || !isReady}
          className={`flex-[2] flex items-center justify-center gap-2 py-3 text-white font-bold rounded-xl text-sm transition-all active:scale-[0.97] shadow-lg disabled:opacity-50 disabled:cursor-not-allowed ${btnColor}`}
        >
          {publishBtnContent()}
        </button>
      </div>

      <form
        onSubmit={(e) => { e.preventDefault(); handleSubmit(); }}
        className="space-y-6 pb-24 sm:pb-0"
      >
        {/* ΓöÇΓöÇ Desktop sticky toolbar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div className="hidden sm:flex items-center justify-between sticky top-[72px] z-40 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md -mx-6 px-6 py-3 border-b border-gray-100 dark:border-gray-800 shadow-sm">
          <p className="text-sm text-gray-500 font-medium">
            {post ? t("editPost") : t("createPost")}
          </p>
          <div className="flex items-center gap-2.5">
            <button
              type="button"
              onClick={() => handleSubmit("draft")}
              disabled={saving || saved}
              className="flex items-center gap-1.5 px-4 py-2 bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-semibold rounded-xl text-sm hover:bg-gray-200 dark:hover:bg-gray-700 transition-all disabled:opacity-50"
            >
              <Save className="w-3.5 h-3.5" />
              {t("saveDraft")}
            </button>

            <div className="relative">
              <div className="flex rounded-xl overflow-hidden shadow-md">
                <button
                  type="button"
                  onClick={() => handleSubmit(publishMode)}
                  disabled={saving || saved || !isReady}
                  className={`flex items-center gap-2 px-5 py-2 text-white font-bold text-sm transition-all active:scale-[0.97] disabled:opacity-50 disabled:cursor-not-allowed ${btnColor}`}
                >
                  {publishBtnContent()}
                </button>
                <button
                  type="button"
                  onClick={() => setModeOpen(o => !o)}
                  disabled={saving || saved}
                  className={`px-2 py-2 text-white border-l border-white/20 transition-colors ${btnColor}`}
                  aria-label="Change publish mode"
                >
                  <ChevronDown className={`w-4 h-4 transition-transform ${modeOpen ? "rotate-180" : ""}`} />
                </button>
              </div>

              {modeOpen && (
                <div className="absolute right-0 mt-2 w-52 bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-150">
                  {([
                    { mode: "published" as PostStatus, label: t("publishNow"),  icon: <Send className="w-4 h-4 text-red-500" /> },
                    { mode: "draft"     as PostStatus, label: t("saveDraft"), icon: <FileText className="w-4 h-4 text-gray-500" /> },
                    { mode: "scheduled" as PostStatus, label: t("schedule"),       icon: <Calendar className="w-4 h-4 text-blue-500" /> },
                  ] as const).map(({ mode, label, icon }) => (
                    <button
                      key={mode}
                      type="button"
                      onClick={() => { setPublishMode(mode); setModeOpen(false); }}
                      className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-semibold hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors ${publishMode === mode ? "text-red-600 bg-red-50 dark:bg-red-900/20" : "text-gray-700 dark:text-gray-300"}`}
                    >
                      {icon}
                      {label}
                      {publishMode === mode && <CheckCircle2 className="w-3.5 h-3.5 ml-auto text-red-500" />}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Close dropdown when clicking outside */}
        {modeOpen && <div className="fixed inset-0 z-30" onClick={() => setModeOpen(false)} />}

        {/* ΓöÇΓöÇ Schedule date/time picker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        {publishMode === "scheduled" && (
          <div className="p-4 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-2xl flex flex-col sm:flex-row sm:items-center gap-3">
            <Calendar className="w-5 h-5 text-blue-600 flex-shrink-0" />
            <div className="flex-1">
              <label className="block text-sm font-semibold text-blue-700 dark:text-blue-400 mb-1">
                {t("publishDate")}
              </label>
              <input
                type="datetime-local"
                value={scheduleDate}
                onChange={e => { setScheduleDate(e.target.value); setFieldErrors(er => ({ ...er, scheduleDate: undefined })); }}
                min={new Date().toISOString().slice(0, 16)}
                className="w-full px-3 py-2 bg-white dark:bg-gray-800 border border-blue-300 dark:border-blue-700 rounded-xl text-sm text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <FieldError msg={fieldErrors.scheduleDate} />
            </div>
          </div>
        )}

        {/* ΓöÇΓöÇ Title ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div ref={titleRef}>
          <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1.5">
            {t("title")} <span className="text-red-500">*</span>
          </label>
          <input
            type="text"
            value={currentTitle}
            onChange={e => {
              const val = e.target.value;
              if (language === "hi") setTitleHi(val);
              else setTitleEn(val);
              if (val.trim()) setFieldErrors(er => ({ ...er, title: undefined }));
            }}
            placeholder={t("titlePlaceholder")}
            className={`w-full px-4 py-3 bg-gray-50 dark:bg-gray-800 border rounded-xl text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-red-500 text-lg transition-colors ${fieldErrors.title ? "border-red-400 dark:border-red-500 bg-red-50 dark:bg-red-900/10" : "border-gray-200 dark:border-gray-700"}`}
          />
          <FieldError msg={fieldErrors.title} />
        </div>

        {/* ΓöÇΓöÇ Category ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div ref={categoryRef}>
          <div className="flex items-center justify-between mb-2">
            <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300">
              {t("category")} <span className="text-red-500">*</span>
            </label>
            <button
              type="button"
              onClick={() => { setShowNewCatBox(s => !s); setTimeout(() => newCatRef.current?.focus(), 50); }}
              className="flex items-center gap-1.5 px-3 py-1 text-xs font-semibold text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg hover:bg-red-100 dark:hover:bg-red-900/30 transition-all"
            >
              <Plus className="w-3 h-3" />
              {t("createCategory")}
            </button>
          </div>

          {/* Inline new-category creator */}
          {showNewCatBox && (
            <div className="mb-3 flex gap-2 p-3 bg-red-50 dark:bg-red-900/10 border border-red-200 dark:border-red-800 rounded-xl animate-in fade-in slide-in-from-top-1 duration-150">
              <input
                ref={newCatRef}
                type="text"
                value={newCatInput}
                onChange={e => setNewCatInput(e.target.value)}
                onKeyDown={handleNewCatKey}
                placeholder={t("newCategory") + "..."}
                maxLength={30}
                className="flex-1 px-3 py-2 text-sm bg-white dark:bg-gray-800 border border-red-300 dark:border-red-700 rounded-lg text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-red-500"
              />
              <button
                type="button"
                onClick={addCustomCategory}
                disabled={!newCatInput.trim()}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 disabled:bg-gray-300 dark:disabled:bg-gray-700 text-white text-sm font-bold rounded-lg transition-all flex items-center gap-1.5"
              >
                <Plus className="w-3.5 h-3.5" />
                {catLoading ? t("saving") : t("add") || "Add"}
              </button>
              <button
                type="button"
                onClick={() => { setShowNewCatBox(false); setNewCatInput(""); }}
                className="px-2 py-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 rounded-lg transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          )}

          {/* Category grid */}
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
            {CATEGORIES.map(cat => (
              <button
                key={cat.value}
                type="button"
                onClick={() => { setCategory(cat.value); setFieldErrors(er => ({ ...er, category: undefined })); }}
                className={`px-3 py-2 rounded-xl text-xs font-semibold border transition-all ${
                  category === cat.value
                    ? "bg-red-600 text-white border-red-600 shadow-md scale-105"
                    : "bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-gray-200 dark:border-gray-700 hover:border-red-300 hover:text-red-600"
                }`}
              >
                {t(cat.value)}
              </button>
            ))}

            {/* Custom categories */}
            {customCats.map(cat => (
              <div
                key={cat.value}
                className={`relative flex items-center justify-between px-3 py-2 rounded-xl text-xs font-semibold border transition-all ${
                  category === cat.value
                    ? "bg-red-600 text-white border-red-600 shadow-md"
                    : "bg-purple-50 dark:bg-purple-900/20 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-800 hover:border-purple-400"
                }`}
              >
                <button
                  type="button"
                  onClick={() => { setCategory(cat.value); setFieldErrors(er => ({ ...er, category: undefined })); }}
                  className="flex-1 text-left truncate"
                  title={cat.label}
                >
                  {language === "hi" ? cat.label : (cat.labelEn || cat.label)}
                </button>
                <button
                  type="button"
                  onClick={() => removeCustomCat(cat.value)}
                  className={`ml-1 flex-shrink-0 opacity-60 hover:opacity-100 transition-opacity ${
                    category === cat.value ? "text-white" : "text-purple-500 dark:text-purple-400"
                  }`}
                  title={t("deletePost")}
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}
          </div>
          <FieldError msg={fieldErrors.category} />
        </div>

        {/* ΓöÇΓöÇ Location & Event Time ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
        <div className="p-4 rounded-2xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 space-y-4">
          <div className="flex items-center gap-2 mb-1">
            <div className="w-1 h-5 bg-blue-500 rounded-full" />
            <h3 className="text-sm font-bold text-gray-700 dark:text-gray-300">
              {t("locationAndTime")}
              <span className="ml-2 text-[10px] font-medium text-gray-400">{t("optional")}</span>
            </h3>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1.5">
                ≡ƒÅÖ∩╕Å&nbsp;{t("city")}
              </label>
              <input
                type="text"
                value={city}
                onChange={e => setCity(e.target.value)}
                placeholder={language === "hi" ? "αñ£αÑêαñ╕αÑç: αñ¬αñƒαñ¿αñ╛, αñ░αñ╛αñüαñÜαÑÇ..." : "e.g. Patna, Ranchi..."}
                className="w-full px-3 py-2.5 text-sm bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1.5">
                ≡ƒù║∩╕Å&nbsp;{t("state")}
              </label>
              <select
                value={state}
                onChange={e => setState(e.target.value)}
                className="w-full px-3 py-2.5 text-sm bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="">{t("selectStatePrompt")}</option>
                {[
                  ["Bihar","bihar"],
                  ["Jharkhand","jharkhand"],
                  ["Uttar Pradesh","stateUP"],
                  ["Delhi","stateDelhi"],
                  ["West Bengal","stateWB"],
                  ["Maharashtra","stateMH"],
                  ["Madhya Pradesh","stateMP"],
                  ["Rajasthan","stateRJ"],
                  ["Gujarat","stateGJ"],
                  ["Punjab","statePB"],
                  ["Haryana","stateHR"],
                  ["Odisha","stateOD"],
                  ["Chhattisgarh","stateCH"],
                  ["Uttarakhand","stateUK"],
                  ["Assam","stateAS"],
                  ["Other","other"],
                ].map(([en, key]) => (
                  <option key={key} value={en}>{t(key)}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1.5">
                ≡ƒôà&nbsp;{t("eventDate")}
              </label>
              <input
                type="date"
                value={eventDate}
                onChange={e => setEventDate(e.target.value)}
                className="w-full px-3 py-2.5 text-sm bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1.5">
                ΓÅ░&nbsp;{t("eventTime")}
              </label>
              <div className="flex gap-2">
                <select
                  value={timeHour}
                  onChange={e => setTimeHour(e.target.value)}
                  className="flex-1 px-2 py-2.5 text-sm bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">HH</option>
                  {Array.from({ length: 12 }, (_, i) => i + 1).map(h => (
                    <option key={h} value={String(h)}>{String(h).padStart(2, "0")}</option>
                  ))}
                </select>
                <select
                  value={timeMinute}
                  onChange={e => setTimeMinute(e.target.value)}
                  className="flex-1 px-2 py-2.5 text-sm bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl text-gray-900 dark:text-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  {["00","05","10","15","20","25","30","35","40","45","50","55"].map(m => (
                    <option key={m} value={m}>{m}</option>
                  ))}
                </select>
                <div className="flex rounded-xl overflow-hidden border border-gray-200 dark:border-gray-700">
                  {(["AM", "PM"] as const).map(period => (
                    <button
                      key={period}
                      type="button"
                      onClick={() => setTimePeriod(period)}
                      className={`px-3 py-2.5 text-xs font-bold transition-colors ${
                        timePeriod === period
                          ? "bg-blue-600 text-white"
                          : "bg-white dark:bg-gray-800 text-gray-500 dark:text-gray-400 hover:bg-blue-50 dark:hover:bg-blue-900/20"
                      }`}
                    >
                      {language === "hi"
                        ? (period === "AM" ? "αñ¬αÑéαñ░αÑìαñ╡αñ╛αñ╣αÑìαñ¿" : "αñàαñ¬αñ░αñ╛αñ╣αÑìαñ¿")
                        : period}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>

