// lib/firebase/comments.ts
import {
  collection,
  addDoc,
  deleteDoc,
  doc,
  query,
  where,
  orderBy,
  onSnapshot,
  Timestamp,
  increment,
  updateDoc,
  getDocs,
} from "firebase/firestore";
import { db } from "./config";

export interface Comment {
  id: string;
  postId: string;
  userId: string;
  displayName: string;
  photoURL: string;
  comment: string;
  timestamp: string;
  parentId?: string;      // If it's a reply to another comment
  isAdmin?: boolean;      // If the comment is from a publisher/admin
  replyToName?: string;   // Name of the person being replied to
  likesCount?: number;    // Number of likes on this comment
}

// Real-time comments listener
export function subscribeToComments(
  postId: string,
  callback: (comments: Comment[]) => void
): () => void {
  const q = query(
    collection(db, "comments"),
    where("postId", "==", postId)
    // Removed orderBy to avoid requiring composite indexes in production
  );

  const unsubscribe = onSnapshot(q, (snapshot) => {
    const comments: Comment[] = snapshot.docs.map((doc) => {
      const data = doc.data();
      return {
        id: doc.id,
        postId: data.postId,
        userId: data.userId,
        displayName: data.displayName,
        photoURL: data.photoURL,
        comment: data.comment,
        parentId: data.parentId,
        isAdmin: data.isAdmin,
        replyToName: data.replyToName,
        likesCount: data.likesCount || 0,
        timestamp:
          data.timestamp instanceof Timestamp
            ? data.timestamp.toDate().toISOString()
            : data.timestamp,
      };
    });

    // Sort in memory by timestamp ascending
    comments.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
    
    callback(comments);
  });

  return unsubscribe;
}

// Add a comment
export async function addComment(
  postId: string,
  userId: string,
  displayName: string,
  photoURL: string,
  comment: string,
  parentId?: string,
  isAdmin?: boolean,
  replyToName?: string
): Promise<void> {
  await addDoc(collection(db, "comments"), {
    postId,
    userId,
    displayName,
    photoURL,
    comment,
    parentId: parentId || null,
    isAdmin: isAdmin || false,
    replyToName: replyToName || null,
    likesCount: 0,
    timestamp: Timestamp.now(),
  });

  // Update commentsCount on post
  const postRef = doc(db, "posts", postId);
  await updateDoc(postRef, { commentsCount: increment(1) });
}

// Delete a comment
export async function deleteComment(
  commentId: string,
  postId: string
): Promise<void> {
  await deleteDoc(doc(db, "comments", commentId));
  const postRef = doc(db, "posts", postId);
  await updateDoc(postRef, { commentsCount: increment(-1) });
}

// Get comments for a post (one-time fetch)
export async function getComments(postId: string): Promise<Comment[]> {
  const q = query(
    collection(db, "comments"),
    where("postId", "==", postId)
  );
  const snapshot = await getDocs(q);
  const comments = snapshot.docs.map((doc) => {
    const data = doc.data();
    return {
      id: doc.id,
      postId: data.postId,
      userId: data.userId,
      displayName: data.displayName,
      photoURL: data.photoURL,
      comment: data.comment,
      timestamp:
        data.timestamp instanceof Timestamp
          ? data.timestamp.toDate().toISOString()
          : data.timestamp,
    };
  });

  return comments.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
}

// Toggle comment like
export async function toggleCommentLike(
  commentId: string,
  userId: string
): Promise<boolean> {
  const { runTransaction, increment, serverTimestamp } = await import("firebase/firestore");
  const commentRef = doc(db, "comments", commentId);
  const likeRef = doc(db, "comments", commentId, "likes", userId);

  let liked = false;
  await runTransaction(db, async (transaction) => {
    const commentDoc = await transaction.get(commentRef);
    if (!commentDoc.exists()) throw new Error("Comment not found");

    const likeDoc = await transaction.get(likeRef);
    if (likeDoc.exists()) {
      transaction.delete(likeRef);
      transaction.update(commentRef, { 
        likesCount: increment(-1),
        updatedAt: serverTimestamp()
      });
      liked = false;
    } else {
      transaction.set(likeRef, { userId, createdAt: serverTimestamp() });
      transaction.update(commentRef, { 
        likesCount: increment(1),
        updatedAt: serverTimestamp()
      });
      liked = true;
    }
  });

  return liked;
}

// Check if user liked a comment
export async function getUserCommentLike(
  commentId: string,
  userId: string
): Promise<boolean> {
  const { getDoc } = await import("firebase/firestore");
  const likeRef = doc(db, "comments", commentId, "likes", userId);
  const snapshot = await getDoc(likeRef);
  return snapshot.exists();
}

import { adminDb } from "./admin";
import { Post, PostStatus } from "./posts";
import { Timestamp, AggregateField } from "firebase-admin/firestore";

const POSTS_COLLECTION = "posts";
const COMMENTS_COLLECTION = "comments";

/**
 * Get global engagement statistics for the dashboard.
 * SERVER-ONLY logic using Admin SDK for accuracy and performance.
 */
export async function getGlobalStatsAdmin(): Promise<{
  totalPosts: number;
  totalLikes: number;
  totalViews: number;
  totalComments: number;
}> {
  try {
    const postsRef = adminDb.collection(POSTS_COLLECTION);
    const commentsRef = adminDb.collection(COMMENTS_COLLECTION);

    let stats = {
      totalPosts: 0,
      totalLikes: 0,
      totalViews: 0,
      totalComments: 0,
    };

    try {
      // Primary Strategy: High-performance server-side aggregation
      const postsAggregate = await postsRef.aggregate({
        likes: AggregateField.sum('likesCount'),
        views: AggregateField.sum('viewsCount'),
      }).get();

      const postCount = await postsRef.count().get();
      const commentsCount = await commentsRef.count().get();

      stats = {
        totalPosts: postCount.data().count,
        totalLikes: postsAggregate.data().likes || 0,
        totalViews: postsAggregate.data().views || 0,
        totalComments: commentsCount.data().count,
      };
    } catch (aggError) {
      // Aggregate query requires a composite index ΓÇö falls back to manual summation.
      // Create the index at: https://console.firebase.google.com/project/stv-news-bihar/firestore/indexes
      console.debug("Aggregation using manual fallback (composite index not created yet).");
      
      // Secondary Strategy: Manual summation (Safe fallback for small/medium collections)
      const allPosts = await postsRef.get();
      const allComments = await commentsRef.count().get(); // Count usually works even if sum doesn't
      
      let l = 0, v = 0;
      allPosts.forEach(doc => {
        const data = doc.data();
        l += data.likesCount || 0;
        v += data.viewsCount || 0;
      });

      stats = {
        totalPosts: allPosts.size,
        totalLikes: l,
        totalViews: v,
        totalComments: allComments.data().count,
      };
    }

    return stats;
  } catch (error) {
    console.error("Critical error in getGlobalStatsAdmin:", error);
    return { totalPosts: 0, totalLikes: 0, totalViews: 0, totalComments: 0 };
  }
}

function docToPost(doc: FirebaseFirestore.DocumentSnapshot): Post {
  const data = doc.data()!;
  const status: PostStatus =
    data.status || (data.published ? "published" : "draft");

  function toISO(val: unknown): string {
    if (val instanceof Timestamp) return val.toDate().toISOString();
    if (typeof val === "string") return val;
    return "";
  }

  return {
    id: doc.id,
    title: data.title ?? "",
    titleHi: data.titleHi,
    titleEn: data.titleEn,
    slug: data.slug ?? "",
    tags: data.tags ?? [],
    tagsHi: data.tagsHi,
    tagsEn: data.tagsEn,
    category: data.category ?? "",
    city: data.city ?? "",
    state: data.state ?? "",
    eventDate: data.eventDate ?? "",
    eventTime: data.eventTime ?? "",
    imageUrl: data.imageUrl ?? "",
    videoUrl: data.videoUrl,
    createdAt: toISO(data.createdAt),
    updatedAt: toISO(data.updatedAt),
    publishAt: data.publishAt ? toISO(data.publishAt) : undefined,
    likesCount: data.likesCount ?? 0,
    commentsCount: data.commentsCount ?? 0,
    viewsCount: data.viewsCount ?? 0,
    published: status === "published",
    status,
    content: data.content ?? "",
    contentHi: data.contentHi,
    contentEn: data.contentEn,
    searchTokens: data.searchTokens || [],
  };
}

