          return queryTags.some(qt => pTokens.includes(qt.toLowerCase()));
        });
        
      return filtered.slice(skip, skip + pageSize);
    } catch (fallbackErr) {
      console.error("[getPostsByTagServer] Fallback failed:", fallbackErr);
      return [];
    }
  }
}

